+/* ===== PASB project page — editorial (serif display / Inter body / flat white) ===== */
+:root{
+  --bg:#ffffff; --surface:#ffffff; --surface-2:#fbfbfd; --surface-3:#f5f5fa;
+  --ink:#15161c; --text:#2c2e38; --muted:#6b6e7d; --faint:#9a9daa;
+  --line:#e7e7ef; --line-strong:#d5d6e2;
+  --primary:#5b46c9; --primary-d:#42338f; --primary-soft:#efecfb; --primary-bd:#d9d3f4;
+  --risk:#e0574f; --risk-d:#c33f38; --warn:#dc9a13; --ok:#2f9e6b;
+  --radius:10px; --radius-lg:18px;
+  --serif:"Iowan Old Style","Palatino Linotype",Palatino,"Book Antiqua",Georgia,serif;
+  --sans:"Inter",ui-sans-serif,system-ui,-apple-system,"Segoe UI",Roboto,sans-serif;
+  --mono:ui-monospace,"SF Mono","JetBrains Mono",Menlo,Consolas,monospace;
+}
+*{box-sizing:border-box}
+html{scroll-behavior:smooth}
+body{margin:0;font-family:var(--sans);color:var(--text);background:var(--bg);
+  font-size:16px;line-height:1.6;-webkit-font-smoothing:antialiased}
+a{color:var(--primary);text-decoration:none}
+a:hover{color:var(--primary-d)}
+h1,h2,h3{color:var(--ink);letter-spacing:-.01em}
+h2{font-family:var(--serif);font-weight:700;font-size:clamp(1.7rem,3.2vw,2.4rem);margin:0 0 .2rem}
+h3{font-weight:700;font-size:1.15rem;margin:0 0 .4rem}
+.wrap{max-width:1120px;margin:0 auto;padding:0 1.5rem}
+.section{padding:3.4rem 0}
+.eyebrow{font-family:var(--mono);font-size:.72rem;letter-spacing:.18em;text-transform:uppercase;color:var(--primary);font-weight:600;margin:0 0 .5rem}
+.lead{color:var(--muted);max-width:60rem;font-size:1.02rem}
+.center{text-align:center}
+.center .lead{margin-left:auto;margin-right:auto}
+code,.mono{font-family:var(--mono)}
+
+/* ---- floating pill nav ---- */
+.nav-veil{position:sticky;top:0;z-index:50;background:linear-gradient(180deg,rgba(255,255,255,.97) 60%,rgba(255,255,255,0));padding:.7rem 0 1rem}
+.nav{max-width:1120px;margin:0 auto;display:flex;align-items:center;gap:.6rem;
+  background:rgba(255,255,255,.9);backdrop-filter:blur(8px);border:1px solid var(--line);
+  border-radius:999px;padding:.4rem .5rem .4rem .9rem}
+.nav .brand{display:flex;align-items:center;gap:.5rem;font-weight:800;color:var(--ink);letter-spacing:-.02em;font-size:1.05rem}
+.nav .brand .mk{width:22px;height:22px;border-radius:6px;background:var(--primary);display:inline-grid;place-items:center;color:#fff;font-size:.7rem;font-weight:800;font-family:var(--mono)}
+.nav .links{display:flex;gap:.1rem;margin-left:.6rem}
+.nav .links a{color:var(--text);font-size:.86rem;font-weight:500;padding:.4rem .7rem;border-radius:999px}
+.nav .links a:hover{background:var(--surface-3);color:var(--ink)}
+.nav .util{margin-left:auto;display:flex;gap:.4rem;align-items:center}
+.nav .util a{font-size:.8rem;font-weight:600;padding:.4rem .8rem;border-radius:999px;border:1px solid var(--line);color:var(--text)}
+.nav .util a:hover{border-color:var(--primary);color:var(--primary)}
+.nav .util a.pri{background:var(--primary);border-color:var(--primary);color:#fff}
+.nav .util a.pri:hover{background:var(--primary-d)}
+.nav .burger{display:none}
+@media(max-width:860px){.nav .links{display:none}.nav .util a.hideable{display:none}}
+
+/* ---- hero ---- */
+.hero{padding:2.2rem 0 1.4rem}
+.hero-grid{display:grid;grid-template-columns:1.25fr .9fr;gap:2.4rem;align-items:center}
+@media(max-width:900px){.hero-grid{grid-template-columns:1fr;gap:1.6rem}}
+.hero h1{font-family:var(--serif);font-weight:700;font-size:clamp(2.4rem,5vw,3.7rem);line-height:1.05;margin:.3rem 0 .1rem;text-wrap:balance}
+.hero .sub{font-size:1.12rem;color:var(--muted);margin:.7rem 0 0;max-width:34rem}
+.hero .btns{display:flex;flex-wrap:wrap;gap:.55rem;margin-top:1.4rem}
+.btn{display:inline-flex;align-items:center;gap:.45rem;font-size:.9rem;font-weight:600;padding:.6rem 1.05rem;border-radius:999px;border:1px solid var(--line);color:var(--text);background:#fff;transition:.15s}
+.btn:hover{border-color:var(--primary);color:var(--primary)}
+.btn.pri{background:var(--primary);border-color:var(--primary);color:#fff}
+.btn.pri:hover{background:var(--primary-d);color:#fff}
+.hero-panel{border:1px solid var(--line);border-radius:var(--radius-lg);background:var(--surface-2);padding:1.1rem 1.2rem}
+.hero-panel .ph{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:.6rem}
+.hero-panel .ph b{font-size:.9rem;color:var(--ink)}
+.hero-panel .ph .badge{font-family:var(--mono);font-size:.62rem;text-transform:uppercase;letter-spacing:.08em;color:var(--primary);background:var(--primary-soft);border:1px solid var(--primary-bd);border-radius:999px;padding:.15rem .5rem}
+.mini-row{display:flex;align-items:center;gap:.6rem;padding:.4rem 0;border-top:1px solid var(--line);font-size:.86rem}
+.mini-row .rk{font-family:var(--mono);font-size:.72rem;color:var(--faint);width:1.5rem}
+.mini-row .nm{flex:1;color:var(--ink);font-weight:600}
+.mini-row .vl{font-family:var(--mono);font-weight:700;font-variant-numeric:tabular-nums}
+.mini-tiles{display:grid;grid-template-columns:repeat(3,1fr);gap:.5rem;margin-top:.8rem}
+.mini-tiles .t{text-align:center;background:#fff;border:1px solid var(--line);border-radius:10px;padding:.55rem .2rem}
+.mini-tiles .t b{display:block;font-family:var(--mono);font-weight:800;font-size:1.15rem;color:var(--primary)}
+.mini-tiles .t span{font-size:.66rem;color:var(--muted);letter-spacing:.02em}
+
+/* ---- metric strip ---- */
+.metrics{display:grid;grid-template-columns:repeat(6,1fr);gap:1px;background:var(--line);border:1px solid var(--line);border-radius:var(--radius-lg);overflow:hidden}
+@media(max-width:820px){.metrics{grid-template-columns:repeat(3,1fr)}}
+@media(max-width:520px){.metrics{grid-template-columns:repeat(2,1fr)}}
+.metrics .m{background:#fff;padding:1.2rem .7rem;text-align:center}
+.metrics .m b{display:block;font-family:var(--mono);font-weight:800;font-size:1.6rem;color:var(--ink);letter-spacing:-.02em;font-variant-numeric:tabular-nums}
+.metrics .m span{font-size:.68rem;color:var(--muted);letter-spacing:.03em;text-transform:uppercase;margin-top:.3rem;display:block}
+
+/* ---- generic cards ---- */
+.cards{display:grid;gap:1rem}
+.g3{grid-template-columns:repeat(3,1fr)}.g2{grid-template-columns:repeat(2,1fr)}
+@media(max-width:820px){.g3,.g2{grid-template-columns:1fr}}
+.card{border:1px solid var(--line);border-radius:var(--radius-lg);background:#fff;padding:1.3rem 1.4rem}
+.card.soft{background:var(--surface-2)}
+.card .k{font-family:var(--mono);font-size:.66rem;letter-spacing:.1em;text-transform:uppercase;color:var(--primary);font-weight:600}
+.card p{color:var(--muted);font-size:.92rem;margin:.4rem 0 0}
+.card .big{font-family:var(--mono);font-weight:800;font-size:1.5rem;color:var(--risk)}
+
+/* ---- figure ---- */
+.figure{border:1px solid var(--line);border-radius:var(--radius-lg);background:#fff;padding:1rem;overflow:hidden}
+.figure img{display:block;width:100%;height:auto;border-radius:8px}
+.figcap{font-size:.82rem;color:var(--muted);margin-top:.7rem;text-align:center;line-height:1.5}
+.figcap b{color:var(--ink)}
+
+/* ---- taxonomy chips ---- */
+.taxo{display:grid;grid-template-columns:repeat(4,1fr);gap:.8rem;margin-top:1.1rem}
+@media(max-width:820px){.taxo{grid-template-columns:repeat(2,1fr)}}
+.taxo .tx{border:1px solid var(--line);border-radius:12px;padding:.85rem .9rem;background:#fff}
+.taxo .tx .h{font-weight:700;color:var(--ink);font-size:.92rem;margin-bottom:.15rem}
+.taxo .tx .d{font-size:.78rem;color:var(--muted);line-height:1.4}
+.pill{display:inline-block;font-family:var(--mono);font-size:.7rem;padding:.2rem .55rem;border-radius:999px;border:1px solid var(--line);color:var(--text);background:var(--surface-2);margin:.15rem .2rem 0 0}
+
+/* ---- controls (tabs / selects / filters) ---- */
+.tabs{display:flex;flex-wrap:wrap;gap:.35rem;margin:.2rem 0 1rem}
+.tab{font-size:.84rem;font-weight:600;color:var(--muted);padding:.45rem .9rem;border-radius:999px;border:1px solid var(--line);background:#fff;cursor:pointer;transition:.15s}
+.tab:hover{border-color:var(--primary-bd);color:var(--primary)}
+.tab.on{background:var(--primary);border-color:var(--primary);color:#fff}
+.ctrl-row{display:flex;flex-wrap:wrap;gap:.6rem;align-items:center;margin-bottom:.9rem}
+select,.inp{font-family:var(--sans);font-size:.84rem;color:var(--text);background:#fff;border:1px solid var(--line-strong);border-radius:8px;padding:.42rem .7rem}
+select:focus,.inp:focus{outline:none;border-color:var(--primary)}
+.seg{display:inline-flex;border:1px solid var(--line-strong);border-radius:8px;overflow:hidden}
+.seg button{border:0;background:#fff;font-family:var(--sans);font-size:.8rem;font-weight:600;color:var(--muted);padding:.42rem .8rem;cursor:pointer}
+.seg button.on{background:var(--primary);color:#fff}
+.mut{color:var(--faint);font-size:.8rem;font-family:var(--mono)}
+
+/* ---- leaderboard table ---- */
+.tbl-wrap{border:1px solid var(--line);border-radius:var(--radius-lg);overflow-x:auto;background:#fff}
+table.lb{width:100%;border-collapse:collapse;font-size:.86rem;min-width:640px}
+table.lb th,table.lb td{padding:.6rem .7rem;text-align:right;white-space:nowrap;border-bottom:1px solid var(--line)}
+table.lb th{position:sticky;top:0;background:var(--surface-3);font-size:.7rem;letter-spacing:.04em;text-transform:uppercase;color:var(--muted);font-weight:700;cursor:pointer;user-select:none}
+table.lb th:first-child,table.lb td:first-child{text-align:center;color:var(--faint);font-family:var(--mono)}
+table.lb th.name,table.lb td.name{text-align:left}
+table.lb td.name{font-weight:700;color:var(--ink)}
+table.lb td .org{display:block;font-weight:500;font-size:.72rem;color:var(--faint)}
+table.lb tbody tr:hover{background:var(--surface-2)}
+table.lb th.on{color:var(--primary)}
+table.lb td.v{font-family:var(--mono);font-variant-numeric:tabular-nums}
+table.lb td.avg{font-weight:800}
+.heat{border-radius:5px;padding:.12rem .4rem;color:#fff;font-weight:700}
+.chip-fw{font-family:var(--mono);font-size:.62rem;padding:.1rem .4rem;border-radius:5px;border:1px solid var(--line)}
+.chip-fw.H{color:#5b46c9;background:var(--primary-soft);border-color:var(--primary-bd)}
+.chip-fw.OC{color:#0e7c86;background:#e4f5f6;border-color:#bfe6e9}
+
+/* ---- matrix / heatmap grid ---- */
+.matrix{border:1px solid var(--line);border-radius:var(--radius-lg);overflow-x:auto;background:#fff;padding:.5rem}
+table.mx{border-collapse:collapse;font-size:.78rem;margin:0 auto}
+table.mx th,table.mx td{padding:.4rem .5rem;text-align:center}
+table.mx th{color:var(--muted);font-weight:600;font-size:.7rem}
+table.mx th.rl{text-align:right;color:var(--ink);font-weight:700;white-space:nowrap;padding-right:.7rem}
+table.mx td .cell{min-width:44px;border-radius:6px;padding:.35rem .1rem;color:#fff;font-family:var(--mono);font-weight:700;font-variant-numeric:tabular-nums;font-size:.76rem}
+table.mx td.blank .cell{background:repeating-linear-gradient(45deg,#f0f0f5,#f0f0f5 4px,#e9e9f1 4px,#e9e9f1 8px);color:var(--faint)}
+.legend{display:flex;align-items:center;gap:.5rem;font-size:.74rem;color:var(--muted);margin-top:.6rem;justify-content:center}
+.legend .bar{height:10px;width:150px;border-radius:6px;background:linear-gradient(90deg,#2f9e6b,#dc9a13,#e0574f)}
+
+/* ---- episode browser ---- */
+.epx{display:grid;grid-template-columns:340px 1fr;gap:1rem}
+@media(max-width:900px){.epx{grid-template-columns:1fr}}
+.eplist{border:1px solid var(--line);border-radius:var(--radius-lg);background:#fff;max-height:640px;overflow-y:auto}
+.epitem{display:block;width:100%;text-align:left;border:0;border-bottom:1px solid var(--line);background:#fff;padding:.7rem .85rem;cursor:pointer;font:inherit}
+.epitem:hover{background:var(--surface-2)}
+.epitem.on{background:var(--primary-soft)}
+.epitem .top{display:flex;gap:.4rem;align-items:center;margin-bottom:.2rem}
+.epitem .top .nm{font-weight:700;color:var(--ink);font-size:.84rem}
+.epitem .meta{font-size:.72rem;color:var(--muted);font-family:var(--mono)}
+.epitem .dots{display:flex;gap:2px;margin-top:.35rem}
+.dot{width:15px;height:15px;border-radius:4px;font-size:.6rem;display:grid;place-items:center;color:#fff;font-weight:700;font-family:var(--mono)}
+.epdetail{border:1px solid var(--line);border-radius:var(--radius-lg);background:#fff;padding:1.2rem 1.3rem;min-height:420px}
+.claimbox{background:var(--surface-2);border:1px solid var(--line);border-left:3px solid var(--primary);border-radius:8px;padding:.7rem .9rem;font-size:.9rem;color:var(--ink)}
+.stage-h{font-family:var(--mono);font-size:.68rem;letter-spacing:.1em;text-transform:uppercase;color:var(--primary);font-weight:700;margin:1.1rem 0 .5rem;display:flex;align-items:center;gap:.5rem}
+.stage-h::after{content:"";flex:1;height:1px;background:var(--line)}
+.turn{border:1px solid var(--line);border-radius:9px;padding:.5rem .7rem;margin-bottom:.5rem;font-size:.83rem}
+.turn .u{color:var(--ink);white-space:pre-wrap;word-break:break-word}
+.turn .a{color:var(--muted);margin-top:.3rem;padding-top:.3rem;border-top:1px dashed var(--line);white-space:pre-wrap;word-break:break-word}
+.turn .a.clamped{max-height:9.5em;overflow:hidden;position:relative}
+.turn .a.clamped::after{content:"";position:absolute;left:0;right:0;bottom:0;height:2.4em;background:linear-gradient(180deg,rgba(255,255,255,0),#fff)}
+.turn .a.show{max-height:none}
+.turn .a.show::after{display:none}
+.turn .more{font:inherit;font-size:.72rem;font-weight:700;color:var(--primary);background:none;border:0;cursor:pointer;padding:.2rem 0 0}
+.turn .more:hover{text-decoration:underline}
+.turn .role{font-family:var(--mono);font-size:.62rem;text-transform:uppercase;letter-spacing:.06em;color:var(--faint);margin-right:.35rem}
+.commitbox{border:1px solid var(--risk);border-radius:9px;background:#fdf3f2;padding:.6rem .8rem;font-family:var(--mono);font-size:.78rem;white-space:pre-wrap;color:#6a2a26;max-height:180px;overflow:auto}
+.commitbox.empty{border-color:var(--ok);background:#eefaf3;color:#1d6b4a}
+.commit-lbl{font-family:var(--mono);font-size:.66rem;color:var(--faint);text-transform:uppercase;letter-spacing:.06em;display:block;margin:.5rem 0 .2rem}
+.scoreline{display:flex;gap:.35rem;flex-wrap:wrap;margin-top:.35rem}
+.scorepill{font-family:var(--mono);font-size:.66rem;padding:.12rem .4rem;border-radius:5px;border:1px solid var(--line);color:#fff;font-weight:700}
+
+/* ---- capability ladder ---- */
+.ladder{display:grid;gap:.5rem}
+.rung{display:grid;grid-template-columns:auto 1fr;gap:.9rem;align-items:start;border:1px solid var(--line);border-radius:12px;padding:.8rem 1rem;background:#fff}
+.rung .lv{font-family:var(--mono);font-weight:800;color:#fff;background:var(--primary);border-radius:8px;padding:.35rem .55rem;font-size:.8rem;height:fit-content}
+.rung .h{font-weight:700;color:var(--ink)}
+.rung .d{font-size:.85rem;color:var(--muted)}
+
+/* ---- bibtex ---- */
+.bibtex{background:#0f1016;color:#d7d9e6;border-radius:var(--radius-lg);padding:1.1rem 1.3rem;overflow-x:auto;font-family:var(--mono);font-size:.78rem;line-height:1.65;position:relative}
+.copy-btn{position:absolute;top:.7rem;right:.7rem;font-family:var(--sans);font-size:.72rem;font-weight:600;color:#cfd2e6;background:#26283a;border:1px solid #3a3d55;border-radius:6px;padding:.3rem .6rem;cursor:pointer}
+.copy-btn:hover{background:#33364c}
+
+/* ---- footer ---- */
+footer{border-top:1px solid var(--line);padding:2rem 0;color:var(--muted);font-size:.85rem}
+footer a{font-weight:600}
+.dim{color:var(--faint)}
+.hr{height:1px;background:var(--line);border:0;margin:0}
+.caution{font-size:.82rem;color:var(--muted);border:1px solid var(--line);border-left:3px solid var(--warn);border-radius:8px;padding:.55rem .8rem;background:#fffdf5}

